func (u *ProductReservationUpsertBulk) UpdateNewValues() *ProductReservationUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithNewValues())
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(s *sql.UpdateSet) {
		for _, b := range u.create.builders {
			if _, exists := b.mutation.ID(); exists {
				s.SetIgnore(productreservation.FieldID)
			}
			if _, exists := b.mutation.CreatedAt(); exists {
				s.SetIgnore(productreservation.FieldCreatedAt)
			}
			if _, exists := b.mutation.ProductID(); exists {
				s.SetIgnore(productreservation.FieldProductID)
			}
			if _, exists := b.mutation.InvoiceID(); exists {
				s.SetIgnore(productreservation.FieldInvoiceID)
			}
			if _, exists := b.mutation.UserID(); exists {
				s.SetIgnore(productreservation.FieldUserID)
			}
		}
	}))
	return u
}

